var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"하아...... 하아......!","JPN":"はあ……はあ……！","ENG":"*Huff... Huff...*","TWN":"哈啊……哈啊……！"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"분명히 내 공격을 정면으로 맞은 것 같은데...... 어떻게 살아 있는 거지?","JPN":"確かに俺の攻撃を正面から受けたはずだが……なんで生きているんだ？","ENG":"I was pretty sure my attack landed right on you... How did you survive that?","TWN":"明明正面擊中了她……為什麼沒死？"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"맷집이 좋은 건지, 내가 힘 조절에 실패한 건지 모르겠군.","JPN":"打たれ強いのか、俺が手加減に失敗したのかわからないな。","ENG":"I don't know if you took the blow well or if I went too easy on you.","TWN":"不知道是妳耐打，還是我沒調整好力道。"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"어쨌든 숨바꼭질은 끝났어.","JPN":"とにかく、かくれんぼはおしまいだ。","ENG":"In any case, enough with the hide and seek.","TWN":"不管怎樣，捉迷藏就到此為止吧。"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"슬슬 엎드려서 빌어 보는 게 어때.","JPN":"そろそろ命乞いでもしたらどうだ。","ENG":"Why don't you get on your knees and beg?","TWN":"不如出來乖乖投降吧。"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"정성을 생각해서 목숨만은 살려 줄지도 모르잖아.","JPN":"ここまで耐えた努力を称えて、命だけは助けてやるかもしれんぞ。","ENG":"Maybe I'll be generous and let you live.","TWN":"說不定我會饒妳一命。"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"네놈들에게 엎드리느니 차라리 내 손으로 머리통에 총알을 박겠어.","JPN":"お前らに命乞いをするなら、自分で頭をぶち抜いて死んだ方がマシだ。","ENG":"I'd rather shoot myself in the head than kneel before you scumbags.","TWN":"向你投降，還不如親手開槍射穿我的頭顱。"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"힘 자랑은 다 끝났나 보지? 그럼 이젠 내 차례야.","JPN":"力自慢はもう終わりか？　じゃあ、私の番だ。","ENG":"You done flexing your stuff? Then it's my turn now.","TWN":"你的表演結束了嗎？那接下來就輪到我了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"수류탄? 또 가짜 모형이냐?","JPN":"手榴弾？　また偽物か？","ENG":"A grenade? Is that one of your plastic toys again?","TWN":"手榴彈？又是那個玩具嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"가짜인지 아닌지는 네 몸으로 직접 확인해 보시지.","JPN":"偽物かどうか、その体で確かめてみろ。","ENG":"Why don't you find out for yourself?","TWN":"你來親自體驗一下是不是假的。"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"뭐야? 어디로 던지는 거냐?","JPN":"なんだ？　どこに投げるんだ？","ENG":"Huh? Where are you throwing that thing?","TWN":"什麼？妳往哪裡扔？"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"자포자기라도 했나? 이래서야 일부러 놀라줄 수도 없잖아.","JPN":"もう諦めモードか？　これじゃビックリするふりもできねえな。","ENG":"Are you just giving up now? I don't even know how to react to that.","TWN":"自暴自棄了嗎？這也太無趣了吧。"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"글쎄. 자포자기인지 어떤지는......","JPN":"さあね。諦めなのかどうかは……","ENG":"Well, we'll see about that...","TWN":"是不是自暴自棄……"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"하늘이 대답해 주겠지.","JPN":"空が教えてくれるさ。","ENG":"Heads up!","TWN":"老天會告訴你答案。"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"......뭐?","JPN":"……は？","ENG":"What?","TWN":"……什麼？"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"크으윽......","JPN":"くうっ……","ENG":"Ugh...","TWN":"呃啊啊……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"천장을 통째로 무너트리다니, 미리 기둥을 약화시켜 둔 건가?","JPN":"天井を丸ごと崩すとは、事前に柱を壊していたのか。","ENG":"How did she bring down the ceiling? Did she damage the pillars beforehand?","TWN":"竟然直接炸毀了天花板，難道事先弱化了柱子？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"이래서야 함정이라기보다는 자폭 돌격이잖아.","JPN":"これじゃあ罠どころか自爆特攻じゃないか。","ENG":"This isn't so much a trap as it's a kamikaze.","TWN":"這哪是陷阱，這是自爆突擊吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"이 자식들은 대체 무슨 생각으로...... 응?","JPN":"こいつら、いったいどういうつもりで……ん？","ENG":"What the hell are these maniacs thinking—huh?","TWN":"他們到底在想什麼呀……嗯？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"......뭐야, 화물 트럭?","JPN":"……なんだ、貨物トラック？","ENG":"A cargo truck?","TWN":"……什麼，卡車？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"아니, 화물이 아니라 널 태우고 갈 불지옥행 우등 차편이지!","JPN":"いいや、貨物ではなくお前を地獄まで運ぶ特急便だ！","ENG":"Nope! This is your first-class ride to hell!","TWN":"不，不是卡車，是要載著你開往地獄的客車！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"끄아아아악!!!","JPN":"グアアアァッ……！","ENG":"Aaaagh!","TWN":"啊啊啊啊啊！！！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이 정도 충격이라면 하급 카운터에게는 치명적이지.","JPN":"この衝撃なら下級カウンターには致命傷だろ。","ENG":"This impact should be fatal enough for a low-grade Counter.","TWN":"對低級制裁者來說，這種程度的衝擊力是致命的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"혹시 이세계에서 환생이라도 하면 다음 생에는 착하게 살라고.","JPN":"もし異世界で生まれ変わるなら、次の人生は善良に生きろよ。","ENG":"I hope you have a nice little reunion with your crossbow-wielding buddy.","TWN":"但願你在下輩子能成為一個善良的人。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"콜록, 콜록......!","JPN":"ゲホ、ゲホ……！","ENG":"*Cough, cough*","TWN":"咳咳，咳咳……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"젠장, 나까지 깔려 죽을 뻔 했잖아? 무슨 생각이야, 대체?","JPN":"くそっ、私まで下敷きになりかけただろ！　無茶にもほどがある！","ENG":"What the hell? I could've died too! What were you thinking?","TWN":"該死，我也差點被壓死了。你到底在想什麼？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......예전부터 넌 몸이 튼튼했으니까. 이 정도로는 안 죽을 줄 알았어.","JPN":"……お前は昔から体だけは丈夫だろう。その程度じゃ死なないと信じていたよ。","ENG":"You've always been pretty sturdy. I knew that couldn't kill you.","TWN":"……妳的身體那麼結實，我知道妳不會這麼容易就死的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_DOOR_CAR"},{"id":"L46_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"무슨 바보 같은 소릴...... 그보다 이 트럭은 대체 어디서 구해 온 거야?","JPN":"ふざけやがって……それより、このトラックはどこから持ってきたの？","ENG":"What a load of crap... Where did you even get this truck anyway?","TWN":"淨說些垃圾話……這卡車到底是從哪裡弄來的？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"무기상 영감이 뒷문에 준비해 뒀더군.","JPN":"武器屋のジジイが裏に用意していた。","ENG":"The gunsmith had it parked out back.","TWN":"武器商老頭在後門準備了一輛。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"무기상이란 게 안정적인 직업은 아니니까.","JPN":"武器屋なんて安定している職業じゃないからな。","ENG":"He's not exactly in the most stable line of business.","TWN":"畢竟武器商不是一個穩定的工作。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"급할 때 언제든지 떠날 수 있게 창고 대용으로 쓰려던 거겠지.","JPN":"いざという時いつでも逃げられるように、倉庫代わりに使おうとしたんだろう。","ENG":"He was probably using it for storage, in case he had to skip town.","TWN":"平時當倉庫用，有突發情況時隨時可以開走。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그런 걸 마음대로 가지고 와도 되는 거야?","JPN":"そんなもの勝手に持ってきていいのか？","ENG":"And you just took it?","TWN":"你這樣隨便開過來真的沒問題嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"자기 가게를 습격한 악당 놈을 처리하기 위해 잠시 빌린 거니까 이해해 주겠지.","JPN":"自分の店に襲撃してきた悪党を処理するために少しの間借りただけだし、理解してくれるだろう。","ENG":"I'm sure he'll understand since we used it to get rid of the hooligan who trashed his shop.","TWN":"我是為了幹掉襲擊他的店鋪的壞人才借來的，應該會理解吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그보다 빨리 상점으로 돌아가자.","JPN":"それより、はやく店に戻ろう。","ENG":"Speaking of which, we'd better hurry back there.","TWN":"快回到商店裡吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"지훈이도 계속 버틸 수는 없을 거다.","JPN":"ゴトウも長時間耐えるのは厳しいだろう。","ENG":"Jihoon's not going to last much longer.","TWN":"智勳應該撐不了太久。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};